import { Routes, Route, useLocation } from "react-router-dom";
import Sidebar from "./Sidebar";

import AuthForm from "./AuthForm";
import Dashboard from "./Dashboard";
import Tasks from "./Tasks";
import Notes from "./Notes";
import HabitTracker from "./HabitTracker";
import Analytics from "./Analytics";
import Settings from "./Settings";
import NotFound from "./NotFound";
import ProtectedRoute from "./ProtectedRoute.js";

function App() {
  const location = useLocation();

 const validRoutes = [
  "/",
  "/dashboard",
  "/tasks",
  "/notes",
  "/habits",
  "/analytics",
  "/settings"
];

const hideSidebar =
  location.pathname === "/" ||
  !validRoutes.includes(location.pathname);

  return (
    <div style={{ display: "flex" }}>

      {!hideSidebar && <Sidebar />}

      <div
        style={{
          marginLeft: !hideSidebar ? "220px" : "0",
          width: "100%",
          padding: "20px",
        }}
      >
        <Routes>

          <Route path="/" element={<AuthForm />} />

          <Route
            path="/dashboard"
            element={
              <ProtectedRoute>
                <Dashboard />
              </ProtectedRoute>
            }
          />

          <Route
            path="/tasks"
            element={
              <ProtectedRoute>
                <Tasks />
              </ProtectedRoute>
            }
          />

          <Route
            path="/notes"
            element={
              <ProtectedRoute>
                <Notes />
              </ProtectedRoute>
            }
          />

          <Route
            path="/habits"
            element={
              <ProtectedRoute>
                <HabitTracker />
              </ProtectedRoute>
            }
          />

          <Route
            path="/analytics"
            element={
              <ProtectedRoute>
                <Analytics />
              </ProtectedRoute>
            }
          />

          <Route
            path="/settings"
            element={
              <ProtectedRoute>
                <Settings />
              </ProtectedRoute>
            }
          />

          <Route path="*" element={<NotFound />} />

        </Routes>
      </div>

    </div>
  );
}

export default App;
